import{_ as l,H as i,f as a,i as r}from"./chunks/framework.eFU6Tutu.js";const e="/assets/pizza_margarita.BFnMkm6l.jpg",o="/assets/pesto.BWaHgunk.jpg",s="/assets/basil_pasta.gN8TJnHa.jpg",m=JSON.parse('{"title":"Готовые идеи рецептов с базиликом","description":"","frontmatter":{},"headers":[],"relativePath":"recipes/basil.md","filePath":"recipes/basil.md"}'),d={name:"recipes/basil.md"};function n(h,t,p,g,c,b){return i(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="готовые-идеи-рецептов-с-базиликом" tabindex="-1">Готовые идеи рецептов с базиликом <a class="header-anchor" href="#готовые-идеи-рецептов-с-базиликом" aria-label="Permalink to &quot;Готовые идеи рецептов с базиликом&quot;">​</a></h1><p>Сборник идей, как использовать базилик.</p><h2 id="пицца-маргарита" tabindex="-1">Пицца Маргарита <a class="header-anchor" href="#пицца-маргарита" aria-label="Permalink to &quot;Пицца Маргарита&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;"><div><p><strong>Ингредиенты (на 2 пиццы):</strong></p><p><strong>Для теста:</strong></p><ul><li>Мука — 500 г</li><li>Вода — 250 мл</li><li>Сухие дрожжи — 5 г</li><li>Оливковое масло — 2 ст. ложки</li><li>Сахар — 1 ч. ложка</li><li>Соль — 1 ч. ложка</li></ul><p><strong>Для начинки:</strong></p><ul><li>Моцарелла — 200 г</li><li>Помидоры черри — 8 шт.</li><li>Томатная паста — 2 ст. ложки</li><li>Базилик свежий — 1 пучок</li><li>Чеснок — 1 зубчик</li><li>Оливковое масло — для смазывания</li></ul><h3 id="калорииность-на-100-г" tabindex="-1">Калорийность на 100 г <a class="header-anchor" href="#калорииность-на-100-г" aria-label="Permalink to &quot;Калорийность на 100 г&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>8 г</td><td>9 г</td><td>28 г</td><td>225</td></tr></tbody></table></div><div><p><img src="'+e+'" alt="Пицца Маргарита с базиликом"></p></div></div><h3 id="приготовление-1-ч" tabindex="-1">Приготовление (1 ч) <a class="header-anchor" href="#приготовление-1-ч" aria-label="Permalink to &quot;Приготовление (1 ч)&quot;">​</a></h3><p><strong>Тесто:</strong></p><ol><li>Растворите в тёплой воде (37-40°C) сахар и дрожжи. Оставьте на 10-15 минут до появления пенной «шапочки».</li><li>Добавьте соль, оливковое масло и постепенно всыпайте муку.</li><li>Замесите мягкое, слегка липкое тесто. Сформируйте шар, смажьте маслом, накройте и уберите в тёплое место на 30-40 минут.</li></ol><p><strong>Соус и начинка:</strong></p><ol><li>На сковороде разогрейте масло и слегка обжарьте раздавленный зубчик чеснока (1-2 минуты). Удалите чеснок.</li><li>Добавьте томатную пасту, немного воды (если густая), соль. Прогрейте 2 минуты. Снимите с огня и добавьте измельчённый базилик.</li><li>Нарежьте моцареллу ломтиками толщиной 3-5 мм. Помидоры черри разрежьте пополам.</li></ol><p><strong>Сборка и выпечка:</strong></p><ol><li>Разогрейте духовку до 220°C.</li><li>Раскатайте тесто в тонкий круг (3-5 мм), сформируйте бортик.</li><li>Смажьте тесто томатным соусом, сверху распределите моцареллу и половинки помидоров.</li><li>Выпекайте 10-15 минут на средней полке до золотистого цвета.</li><li>Готовую пиццу украсьте свежими листьями базилика и сбрызните оливковым маслом.</li></ol><blockquote><p><strong>Совет:</strong> Идеальная температура для пиццы — 220-250°C. Чем горячее духовка, тем быстрее пропечётся тесто и останется хрустящим. Не перегружайте пиццу начинкой, иначе основа может не пропечься.</p></blockquote><h2 id="соус-песто-на-зиму-из-базилика" tabindex="-1">Соус песто на зиму из базилика <a class="header-anchor" href="#соус-песто-на-зиму-из-базилика" aria-label="Permalink to &quot;Соус песто на зиму из базилика&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;"><div><p><strong>Ингредиенты:</strong></p><ul><li>Базилик (зелёный) — большой пучок (только листья)</li><li>Орехи (грецкие или кедровые) — 50 г</li><li>Чеснок — 2 зубчика</li><li>Сок лимона — 1 ст. ложка</li><li>Растительное или оливковое масло — 100 мл</li><li>Соль, перец — по вкусу</li></ul><p><strong>Калорийность на 100 г:</strong></p><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>3 г</td><td>45 г</td><td>4 г</td><td>420</td></tr></tbody></table></div><div><p><img src="'+o+'" alt="Соус песто из базилика"></p></div></div><h3 id="приготовление-30-мин" tabindex="-1">Приготовление (30 мин) <a class="header-anchor" href="#приготовление-30-мин" aria-label="Permalink to &quot;Приготовление (30 мин)&quot;">​</a></h3><ol><li>Подготовьте банки и крышки — простерилизуйте их.</li><li>Орехи слегка подсушите на сухой сковороде (2 минуты).</li><li>У базилика возьмите только листья. Чеснок очистите.</li><li>В чашу блендера сложите орехи, листья базилика, чеснок, соль, перец, лимонный сок и половину масла.</li><li>Измельчайте до однородной пасты с мелкими кусочками (не в пыль!). Попробуйте, отрегулируйте вкус.</li><li>Готовый соус выложите в стерильные банки, оставив 1–1.5 см до края.</li><li>Сверху залейте оставшееся масло так, чтобы оно покрывало соус — это увеличит срок хранения.</li><li>Плотно закройте крышками и уберите в холодильник. Соус также можно заморозить (например, в формах для льда).</li></ol><blockquote><p><strong>Совет:</strong> Классический песто готовится с кедровыми орехами и пармезаном, но этот вариант без сыра отлично подходит для длительного хранения на зиму. При подаче к пасте можно добавить тёртый пармезан прямо в тарелку.</p></blockquote><h2 id="паста-с-баклажанами-и-базиликом" tabindex="-1">Паста с баклажанами и базиликом <a class="header-anchor" href="#паста-с-баклажанами-и-базиликом" aria-label="Permalink to &quot;Паста с баклажанами и базиликом&quot;">​</a></h2><div style="display:grid;grid-template-columns:1fr 1fr;gap:20px;"><div><p><strong>Ингредиенты (на 2 порции):</strong></p><ul><li>Паста (спагетти или орекьетте) — 120 г</li><li>Баклажаны — 1 шт. (200 г)</li><li>Томатный сок (или томаты в с/с) — 300 мл</li><li>Базилик — 1 пучок</li><li>Чеснок — 2 зубчика</li><li>Сливочное масло — 30 г</li><li>Пармезан — 30 г</li><li>Соль, перец — по вкусу</li></ul><p><strong>Калорийность на 100 г (готового блюда):</strong></p><table tabindex="0"><thead><tr><th>Белки</th><th>Жиры</th><th>Углеводы</th><th>Ккал</th></tr></thead><tbody><tr><td>5 г</td><td>7 г</td><td>19 г</td><td>159</td></tr></tbody></table></div><div><p><img src="'+s+'" alt="Паста с баклажанами и базиликом"></p></div></div><h3 id="приготовление-40-мин" tabindex="-1">Приготовление (40 мин) <a class="header-anchor" href="#приготовление-40-мин" aria-label="Permalink to &quot;Приготовление (40 мин)&quot;">​</a></h3><ol><li><strong>Подготовьте овощи:</strong> Баклажан нарежьте небольшими кубиками. Чеснок пропустите через пресс. Базилик измельчите (часть оставьте для подачи).</li><li><strong>Приготовьте соус:</strong> В сотейнике растопите сливочное масло. Обжарьте баклажаны с базиликом 7–10 минут. Добавьте томатный сок, чеснок, соль и перец. Тушите под крышкой 10–15 минут до готовности.</li><li><strong>Сварите пасту:</strong> Отварите пасту в подсоленной воде согласно инструкции до состояния <em>аль денте</em>. Слейте воду, но не промывайте.</li><li><strong>Сервируйте:</strong> Разложите пасту по тарелкам. Сверху выложите соус из баклажанов. Посыпьте тертым пармезаном и оставшимся свежим базиликом.</li></ol><blockquote><p><strong>Совет:</strong> Чтобы убрать горечь из баклажанов, нарежьте их, посолите, оставьте на 10 минут, затем слейте сок и промойте. Для более насыщенного вкуса обжарьте баклажаны до золотистой корочки.</p></blockquote><h2 id="другие-рецепты-с-зеленью" tabindex="-1">Другие рецепты с зеленью: <a class="header-anchor" href="#другие-рецепты-с-зеленью" aria-label="Permalink to &quot;Другие рецепты с зеленью:&quot;">​</a></h2><ul><li><a href="/recipes/mint.html">Мята</a></li><li><a href="/recipes/microgreens.html">Микрозелень</a></li></ul>',24)])])}const _=l(d,[["render",n]]);export{m as __pageData,_ as default};
